INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-01097', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於盛行率、發生率和死亡率，下列何者錯誤？', '["藉由病例對照研究的資料（病例數和對照數）可以估計該疾病之盛行率", "世代研究可以直接估計發生率", "潛在生命年數損失（yearsofpotentiallifelost,YPLL）是衡量早死的指標，可用在協助設定 研究及衛生資源的優先順序，監測早死的趨勢，評估介入計畫的效果", "致死率是衡量疾病嚴重度的指標，它的分母是已經患有該疾病的人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01098', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '研究員欲比較A、B兩工廠員工的死亡率，但僅有A廠員工的年齡分布資料與年齡別死亡率， B廠只有總死亡數和各年齡層人數。此時應選擇何種年齡標準化方法？', '["直接標準化法", "間接標準化法", "需合併兩廠資料重新計算", "僅能比較粗死亡率，無法標準化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01099', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某國公布新生兒平均餘命為80歲，但60歲人口的平均餘命為22歲。下列解釋何者正確？', '["數據矛盾，因60歲者不可能再活22年", "反映該國60歲後死亡率急遽上升", "符合生命表特性，存活至60歲者之未來存活餘命", "計算錯誤，兩者差值應小於10歲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01100', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於平均餘命及生命表，下列何者錯誤？', '["平均餘命可分兩種，世代平均餘命和當代平均餘命，世代平均餘命一般較少使用，而當代 平均餘命較廣為使用", "平均餘命是一種人口概括性的測量，常用來描述群體的健康狀態，可以用來進行國際間健 康狀態的比較", "使用生命表法計算存活率時，須假設研究期間治療效果改善", "生命表的應用多，例如：可以分析族群的死亡率、存活率、保險費率、計算平均餘命"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01101', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某國長期維持定常人口（stationarypopulation）狀態，每年出生10萬人、死亡10萬人，總人 口1,000萬人。若突然實施生育獎勵使出生率翻倍，5年後最可能觀察到：', '["平均餘命縮短", "人口數與年齡結構保持不變", "總人口數增加至1,100萬人", "年齡結構中的幼年層比例上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01102', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某年度的肺癌死亡率，其分母與下列何者分母相同？', '["肝癌致死率", "肺癌致死率", "肺癌發生率", "意外事故死亡率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01103', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列何種情況適合使用「交互作用」分析而非「效應修飾」？', '["評估吸菸對肺癌風險的效應是否因性別不同而異", "分析吸菸和飲酒對肝癌風險的聯合效應是否超過各自效應的總和", "探討年齡對疫苗保護效果的影響", "比較不同教育程度族群中運動對心血管疾病的保護作用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01104', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於觀察到的相關是否是因果關係，下列敘述何者錯誤？', '["開始暴露到石棉之後3年，發生肺癌。基於時序性（Temporalrelationship），下結論此肺癌 歸因於3年前的石棉暴露", "若是暴露和疾病發生呈劑量效應關係（Dose-ResponseRelationship），是暴露和疾病間為因 果關係的很強證據", "生物學上的贊成性（BiologicPlausibility）指的是和現有的生物學知識一致，但是有時候， 流行病學上的觀察領先於生物學知識", "暴露引起疾病的相對危險性（RelativeRisk,RR）越高，暴露和疾病間為因果關係的可能性 越大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01105', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列關於「族群歸因風險」（PopulationAttributableRisk,PAR）的敘述，何者最恰當？', '["病例對照研究結果無法推估PAR", "PAR代表暴露組中「可歸因於暴露」的疾病發生比例", "PAR反映「若消除某暴露，整體族群可減少的疾病負擔」", "PAR估計過程不該考量族群中的暴露盛行率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01106', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於描述流行病學，下列敘述何者錯誤？', '["病例報告與病例系列，雖僅有描述病例，並無對照組，但仍可以藉此描述協助建構疾病防 治（例如COVID-19的隔離措施）的指引", "病例報告與病例系列的資料是提供建立病因假說的線索", "病例報告與病例系列的資料具有很好的外部效度（externalvalidity）", "描述流行病學可以評估不同族群的健康狀況"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
